import pandas as pd
import matplotlib.pyplot as plt

class WorkoutTracker:
    def __init__(self):
        self.data = pd.DataFrame()

    def import_data(self, app, file_path):
        if app == 'Strava':
            self.data = pd.read_csv(file_path)
        elif app == 'Polar Flow':
            self.data = pd.read_excel(file_path)
        elif app == 'MyFitnessPal':
            self.data = pd.read_json(file_path)
        else:
            raise ValueError('Unsupported app')

    def filter_by_sport(self, sport):
        self.data = self.data[self.data['sport'] == sport]

    def get_overall_stats(self):
        total_distance = self.data['distance'].sum()
        total_time = self.data['duration'].sum()
        avg_heart_rate = self.data['heart_rate'].mean()
        return total_distance, total_time, avg_heart_rate

    def get_heart_rate_zones(self):
        hr_zones = [0, 120, 140, 160, 180, 220]
        hr_time = []
        for i in range(len(hr_zones) - 1):
            time_in_zone = self.data[(self.data['heart_rate'] >= hr_zones[i]) & (self.data['heart_rate'] < hr_zones[i+1])]['duration'].sum()
            hr_time.append(time_in_zone)
        return hr_time

    def plot_progress(self, metric):
        if metric == 'pace':
            self.data['pace'] = self.data['duration'] / self.data['distance']
            self.data.plot(x='date', y='pace')
        elif metric == 'distance':
            self.data.plot(x='date', y='distance')
        plt.show()

