    def import_data(self, source, file_path):
        if source == 'Strava':
            self.data = self.import_strava(file_path)
        elif source == 'Polar Flow':
            self.data = self.import_polar_flow(file_path)
        elif source == 'MyFitnessPal':
            self.data = self.import_myfitnesspal(file_path)
        self.update_sports()

    def import_strava(self, file_path):
        strava_data = pd.read_csv(file_path)
        strava_data['source'] = 'Strava'
        return strava_data

    def import_polar_flow(self, file_path):
        polar_data = pd.read_csv(file_path)
        polar_data['source'] = 'Polar Flow'
        return polar_data

    def import_myfitnesspal(self, file_path):
        myfitnesspal_data = pd.read_csv(file_path)
        myfitnesspal_data['source'] = 'MyFitnessPal'
        return myfitnesspal_data

    def update_sports(self):
        self.sports = self.data['sport'].unique()

    def customize_view(self, sport=None, view_by='mileage'):
        if sport:
            sport_data = self.data[self.data['sport'] == sport]
        else:
            sport_data = self.data

        if view_by == 'mileage':
            return sport_data.groupby('date')['distance'].sum().reset_index()
        elif view_by == 'pace':
            return sport_data.groupby('date')['pace'].mean().reset_index()
        elif view_by == 'heart_rate':
            heart_rate_data = sport_data[sport_data['heart_rate'].notnull()]
            return heart_rate_data.groupby('date')['heart_rate'].mean().reset_index()
        elif view_by == 'time':
            return sport_data.groupby('date')['duration'].sum().reset_index()

    def display_progress(self, view_by='mileage'):
        progress_data = self.customize_view(view_by=view_by)
        plt.figure(figsize=(12, 6))
        if view_by == 'mileage':
            plt.plot(progress_data['date'], progress_data['distance'])
            plt.xlabel('Date')
            plt.ylabel('Total Mileage')
        elif view_by == 'pace':
            plt.plot(progress_data['date'], progress_data['pace'])
            plt.xlabel('Date')
            plt.ylabel('Average Pace')
        elif view_by == 'heart_rate':
            plt.plot(progress_data['date'], progress_data['heart_rate'])
            plt.xlabel('Date')
            plt.ylabel('Average Heart Rate')
        elif view_by == 'time':
            plt.plot(progress_data['date'], progress_data['duration'])
            plt.xlabel('Date')
            plt.ylabel('Total Time')
        plt.title('Workout Progress')
        plt.show()

    def display_intensity_zones(self):
        heart_rate_data = self.data[self.data['heart_rate'].notnull()]
        time_in_zones = {}
        for zone, (lower, upper) in self.intensity_zones.items():
            zone_data = heart_rate_data[(heart_rate_data['heart_rate'] >= lower) & (heart_rate_data['heart_rate'] < upper)]
            time_in_zones[zone] = zone_data['duration'].sum()

        plt.figure(figsize=(8, 6))
        plt.bar(time_in_zones.keys(), time_in_zones.values())
        plt.xlabel('Intensity Zone')
        plt.ylabel('Time (seconds)')
        plt.title('Time Spent in Heart Rate Zones')
        plt.show()

