class WorkoutTracker:
    def __init__(self):
        self.data = pd.DataFrame(columns=['Date', 'Sport', 'Distance', 'Duration', 'Avg_HR', 'Max_HR'])
        self.sports = []
        self.filters = ['Distance', 'Pace', 'Time']

    def import_data(self, source, file_path):
        if source == 'Strava':
            self.data = self.data.append(pd.read_csv(file_path), ignore_index=True)
        elif source == 'Polar Flow':
            self.data = self.data.append(pd.read_excel(file_path), ignore_index=True)
        elif source == 'MyFitnessPal':
            self.data = self.data.append(pd.read_json(file_path), ignore_index=True)
        self.data['Date'] = pd.to_datetime(self.data['Date'])
        self.sports = self.data['Sport'].unique()

    def filter_data(self, sport=None, filter_by='Distance'):
        if sport:
            filtered_data = self.data[self.data['Sport'] == sport]
        else:
            filtered_data = self.data.copy()
        if filter_by == 'Distance':
            return filtered_data.groupby('Date')['Distance'].sum()
        elif filter_by == 'Pace':
            return 1 / (filtered_data['Distance'] / filtered_data['Duration'])
        elif filter_by == 'Time':
            return filtered_data.groupby('Date')['Duration'].sum()

    def display_progress(self, filter_by='Distance'):
        fig, ax = plt.subplots(figsize=(12, 6))
        if filter_by == 'Distance':
            self.filter_data().plot(ax=ax)
            ax.set_ylabel('Total Distance (km)')
        elif filter_by == 'Pace':
            self.filter_data(filter_by='Pace').plot(ax=ax)
            ax.set_ylabel('Average Pace (min/km)')
        elif filter_by == 'Time':
            self.filter_data(filter_by='Time').plot(ax=ax)
            ax.set_ylabel('Total Time (minutes)')
        ax.set_xlabel('Date')
        ax.set_title('Workout Progress')
        plt.show()

    def display_hr_zones(self):
        fig, ax = plt.subplots(figsize=(12, 6))
        hr_zones = [0, 0.6, 0.7, 0.8, 0.9, 1.0]
        colors = ['green', 'yellow', 'orange', 'red', 'purple']
        for i, zone in enumerate(hr_zones[:-1]):
            zone_data = self.data[(self.data['Avg_HR'] >= zone * self.data['Max_HR']) & (self.data['Avg_HR'] < hr_zones[i+1] * self.data['Max_HR'])]
            ax.bar(zone_data['Date'], zone_data['Duration'], bottom=sum(ax.containers[i]), color=colors[i], label=f'{int(zone*100)}%-{int(hr_zones[i+1]*100)}%')
        ax.set_xlabel('Date')
        ax.set_ylabel('Time (minutes)')
        ax.set_title('Time Spent in Heart Rate Zones')
        ax.legend()
        plt.show()

